// ============================================================
// WF03 — Email resume quotidien proprietaire (Neurolia Immo)
// UPDATED: guest_id -> prenom via "Get guests"
// KPI = auj + demain
// property_id -> nom via "Get properties"
// ============================================================

var checkInsToday = $("Check-ins aujourd'hui").all().map(function(i) { return i.json; });
var checkOutsToday = $("Check-outs aujourd'hui").all().map(function(i) { return i.json; });
var checkInsTomorrow = $("Check-ins demain").all().map(function(i) { return i.json; });
var tasks = $("Taches menage aujourd'hui + demain").all().map(function(i) { return i.json; });

var DASHBOARD_URL = $("Config").first().json.DASHBOARD_URL;

// ---- Guests map (guest_id -> guest record) ----
var guests = [];
try {
  guests = $("Get guests").all().map(function(i){ return i.json; });
} catch (e) {
  guests = [];
}
var guestMap = {};
for (var g = 0; g < guests.length; g++) {
  if (guests[g] && guests[g].id) guestMap[guests[g].id] = guests[g];
}

// ---- Properties map ----
var properties = [];
try {
  properties = $("Get properties").all().map(function(i){ return i.json; });
} catch (e2) {
  properties = [];
}
var propMap = {};
for (var p = 0; p < properties.length; p++) {
  if (properties[p] && properties[p].id) propMap[properties[p].id] = properties[p];
}

// ---- Users / owners (dedupe) ----
var allUsers = $("Get tous les owners").all().map(function(i) { return i.json; });

var ownersTmp = allUsers.filter(function(u) {
  return u && u.role === "owner" && u.is_active === true && u.email;
});
var ownerByEmail = {};
for (var oi = 0; oi < ownersTmp.length; oi++) ownerByEmail[ownersTmp[oi].email] = ownersTmp[oi];
var owners = Object.keys(ownerByEmail).map(function(k) { return ownerByEmail[k]; });

if (owners.length === 0) return [{ json: { warning: "Aucun owner actif trouve" } }];

// ---- Date ----
var today = new Date();
function formatDate(d) {
  return d.toLocaleDateString("fr-FR", { weekday: "long", day: "numeric", month: "long", year: "numeric" });
}

// ---- Helpers guest / times / property ----
function guestFirstNameFromId(guestId) {
  if (!guestId || !guestMap[guestId]) return "—";
  var gr = guestMap[guestId];

  var full =
    gr.first_name ||
    gr.firstname ||
    gr.full_name ||
    gr.name ||
    "";

  full = String(full || "").trim();
  if (!full) return "—";
  return full.split(/\s+/)[0] || "—";
}

function getArrivalTime(r) {
  return (r && (r.arrival_time || r.check_in_time || r.checkin_time)) || "-";
}
function getDepartureTime(r) {
  return (r && (r.departure_time || r.check_out_time || r.checkout_time)) || "-";
}
function getPropertyName(r) {
  return (
    (r && (r.property_name)) ||
    (r && r.property && r.property.name) ||
    (r && r.property_id && propMap[r.property_id] && propMap[r.property_id].name) ||
    "-"
  );
}

// ---- Styles ----
var C = {
  terra: "#C45C3B", terraLight: "#FBEAE4",
  dark: "#2D2D2D", text: "#4A4A4A", muted: "#888888",
  border: "#E8E6E3", bgPage: "#F5F4F1", bgSunken: "#FAFAF8",
  warning: "#D97706", warningBg: "#FEF3C7",
  info: "#2563EB"
};
var F = "-apple-system,'Segoe UI',Helvetica,Arial,sans-serif";

// ---- KPI (auj + demain) ----
var pendingTasks = tasks.filter(function(t) { return t && t.status !== "completed"; });
var arrivals48 = checkInsToday.length + checkInsTomorrow.length;
// (si tu veux inclure departs demain, ajoute un node "Check-outs demain" et ajoute-le ici)
var departures48 = checkOutsToday.length;

var kpiHtml =
  '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:' + C.bgSunken + ';border-radius:6px;margin:16px 0;">' +
    '<tr>' +
      '<td width="33%" style="text-align:center;padding:16px 8px;">' +
        '<div style="font-family:' + F + ';font-size:28px;font-weight:700;color:' + C.dark + ';">' + arrivals48 + '</div>' +
        '<div style="font-family:' + F + ';font-size:11px;font-weight:500;text-transform:uppercase;letter-spacing:0.06em;color:' + C.muted + ';margin-top:4px;">Arrivees (auj+dem)</div>' +
      '</td>' +
      '<td width="33%" style="text-align:center;padding:16px 8px;">' +
        '<div style="font-family:' + F + ';font-size:28px;font-weight:700;color:' + C.dark + ';">' + departures48 + '</div>' +
        '<div style="font-family:' + F + ';font-size:11px;font-weight:500;text-transform:uppercase;letter-spacing:0.06em;color:' + C.muted + ';margin-top:4px;">Departs (auj)</div>' +
      '</td>' +
      '<td width="34%" style="text-align:center;padding:16px 8px;">' +
        '<div style="font-family:' + F + ';font-size:28px;font-weight:700;color:' + C.terra + ';">' + pendingTasks.length + '</div>' +
        '<div style="font-family:' + F + ';font-size:11px;font-weight:500;text-transform:uppercase;letter-spacing:0.06em;color:' + C.muted + ';margin-top:4px;">Taches (auj+dem)</div>' +
      '</td>' +
    '</tr>' +
  '</table>';

// ---- Section header ----
function sectionHead(title, count) {
  return '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="margin:28px 0 12px;">' +
    '<tr><td style="border-bottom:2px solid ' + C.border + ';padding-bottom:8px;">' +
      '<span style="font-family:' + F + ';font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:0.08em;color:' + C.muted + ';">' + title + '</span>' +
      ' <span style="display:inline-block;background:' + C.terraLight + ';color:' + C.terra + ';font-size:12px;font-weight:600;padding:2px 8px;border-radius:4px;margin-left:8px;">' + count + '</span>' +
    '</td></tr></table>';
}

function addSectionIfNotEmpty(title, items, htmlFn) {
  if (!items || items.length === 0) return "";
  return sectionHead(title, items.length) + htmlFn(items);
}

// ---- Reservation table ----
function reservationTable(reservations) {
  if (!reservations || reservations.length === 0) {
    return '<p style="font-family:' + F + ';font-size:14px;color:' + C.muted + ';padding:8px 0;">Aucun mouvement.</p>';
  }

  var rows = "";
  rows +=
    '<tr style="background:' + C.bgSunken + ';">' +
      '<td style="padding:8px 12px;font-family:' + F + ';font-size:11px;font-weight:600;text-transform:uppercase;color:' + C.muted + ';">Propriete</td>' +
      '<td style="padding:8px 8px;font-family:' + F + ';font-size:11px;font-weight:600;text-transform:uppercase;color:' + C.muted + ';">Voyageur</td>' +
      '<td style="padding:8px 8px;font-family:' + F + ';font-size:11px;font-weight:600;text-transform:uppercase;color:' + C.muted + ';">Pers.</td>' +
      '<td style="padding:8px 8px;font-family:' + F + ';font-size:11px;font-weight:600;text-transform:uppercase;color:' + C.muted + ';">Arrivee</td>' +
      '<td style="padding:8px 8px;font-family:' + F + ';font-size:11px;font-weight:600;text-transform:uppercase;color:' + C.muted + ';">Depart</td>' +
    '</tr>';

  for (var i = 0; i < reservations.length; i++) {
    var r = reservations[i] || {};
    var propertyName = getPropertyName(r);
    var guestFirst = guestFirstNameFromId(r.guest_id);
    var nbGuests = r.nb_guests || "-";
    var arrival = getArrivalTime(r);
    var departure = getDepartureTime(r);
    var specialReq = r.special_requests || null;

    rows +=
      '<tr style="border-bottom:1px solid ' + C.border + ';">' +
        '<td style="padding:10px 12px;font-family:' + F + ';font-size:14px;font-weight:600;color:' + C.dark + ';">' + propertyName + '</td>' +
        '<td style="padding:10px 8px;font-family:' + F + ';font-size:14px;color:' + C.text + ';">' + guestFirst + '</td>' +
        '<td style="padding:10px 8px;font-family:' + F + ';font-size:13px;color:' + C.muted + ';">' + nbGuests + '</td>' +
        '<td style="padding:10px 8px;font-family:' + F + ';font-size:13px;color:' + C.muted + ';">' + arrival + '</td>' +
        '<td style="padding:10px 8px;font-family:' + F + ';font-size:13px;color:' + C.muted + ';">' + departure + '</td>' +
      '</tr>';

    if (specialReq) {
      rows += '<tr><td colspan="5" style="padding:4px 12px 10px;font-family:' + F + ';font-size:13px;">' +
        '<div style="background:' + C.warningBg + ';border-radius:4px;padding:6px 10px;">' +
        '<strong style="color:' + C.warning + ';">Demande :</strong> ' + specialReq +
        '</div></td></tr>';
    }
  }

  return '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="border:1px solid ' + C.border + ';border-radius:6px;overflow:hidden;">' + rows + '</table>';
}

// ---- Content ----
var contentCommon =
  '<p style="font-family:' + F + ';font-size:14px;color:' + C.muted + ';margin:0 0 20px;">Resume du ' + formatDate(today) + '</p>' +
  kpiHtml;

var sections = "";
sections += addSectionIfNotEmpty("Arrivees aujourd'hui", checkInsToday, reservationTable);
sections += addSectionIfNotEmpty("Departs aujourd'hui", checkOutsToday, reservationTable);
sections += addSectionIfNotEmpty("Arrivees demain", checkInsTomorrow, reservationTable);

// Si tu as ajoute "Check-outs demain"
sections += addSectionIfNotEmpty("Departs demain", (typeof checkOutsTomorrow !== "undefined" ? checkOutsTomorrow : []), reservationTable);

contentCommon += sections;

// ---- Tasks menage (AFFICHER uniquement si > 0) ----
var pendingTasks = tasks.filter(function(t) { return t && t.status !== "completed"; });

function getPropertyNameFromTask(t) {
  return (
    (t && (t.property_name || t.propertyName)) ||
    (t && t.property && t.property.name) ||
    (t && t.property_id && propMap[t.property_id] && propMap[t.property_id].name) ||
    "-"
  );
}

if (pendingTasks.length > 0) {
  contentCommon += sectionHead("Taches menage", pendingTasks.length);

  var taskRows = "";

  for (var i = 0; i < pendingTasks.length; i++) {
    var task = pendingTasks[i] || {};

    var propName = getPropertyNameFromTask(task);
    var taskType = task.task_type || task.type || "-";
    var typeLabel =
      taskType === "checkout_clean" ? "Menage depart" :
      taskType === "checkin_prep" ? "Preparation arrivee" :
      taskType === "deep_clean" ? "Nettoyage approfondi" :
      "Tache";

    var staffName =
      (task.assigned_user && task.assigned_user.full_name) ? task.assigned_user.full_name :
      task.assigned_user_name || "Non assigne";

    var statusLabel =
      task.status === "pending"
        ? '<span style="color:' + C.warning + ';font-weight:600;">En attente</span>'
        : '<span style="color:' + C.info + ';font-weight:600;">En cours</span>';

    var dateStr = task.scheduled_date ? String(task.scheduled_date).slice(0, 10) : "-";

    taskRows +=
      '<tr style="border-bottom:1px solid ' + C.border + ';">' +
        '<td style="padding:10px 12px;font-family:' + F + ';font-size:14px;font-weight:600;color:' + C.dark + ';">' + propName + '</td>' +
        '<td style="padding:10px 8px;font-family:' + F + ';font-size:13px;color:' + C.text + ';">' + typeLabel + '</td>' +
        '<td style="padding:10px 8px;font-family:' + F + ';font-size:13px;color:' + C.text + ';">' + staffName + '</td>' +
        '<td style="padding:10px 8px;font-family:' + F + ';font-size:13px;">' + statusLabel + '</td>' +
        '<td style="padding:10px 8px;font-family:' + F + ';font-size:13px;color:' + C.muted + ';">' + dateStr + '</td>' +
      '</tr>';
  }

  contentCommon +=
    '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="border:1px solid ' + C.border + ';border-radius:6px;overflow:hidden;">' +
      '<tr style="background:' + C.bgSunken + ';">' +
        '<td style="padding:8px 12px;font-family:' + F + ';font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:0.06em;color:' + C.muted + ';">Propriete</td>' +
        '<td style="padding:8px 8px;font-family:' + F + ';font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:0.06em;color:' + C.muted + ';">Type</td>' +
        '<td style="padding:8px 8px;font-family:' + F + ';font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:0.06em;color:' + C.muted + ';">Staff</td>' +
        '<td style="padding:8px 8px;font-family:' + F + ';font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:0.06em;color:' + C.muted + ';">Statut</td>' +
        '<td style="padding:8px 8px;font-family:' + F + ';font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:0.06em;color:' + C.muted + ';">Date</td>' +
      '</tr>' +
      taskRows +
    '</table>';
}

contentCommon += '<table role="presentation" cellpadding="0" cellspacing="0" style="margin:28px auto 0;">' +
  '<tr><td style="background-color:' + C.terra + ';border-radius:4px;">' +
  '<a href="' + DASHBOARD_URL + '/dashboard" style="display:inline-block;padding:12px 28px;font-family:' + F + ';font-size:14px;font-weight:600;color:#FFFFFF;text-decoration:none;">Ouvrir le dashboard &rarr;</a>' +
  '</td></tr></table>';

var subject = "[Neurolia Immo] " + arrivals48 + " arrivee(s) (auj+dem)";

// ---- Send 1 email per owner ----
return owners.map(function(owner) {
  var firstName = String(owner.full_name || "Bonjour").trim().split(/\s+/)[0] || "Bonjour";

  var inner =
    '<h1 style="font-family:' + F + ';font-size:22px;font-weight:700;color:' + C.dark + ';margin:0 0 4px;">Bonjour ' + firstName + ',</h1>' +
    contentCommon;

  var html =
    '<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1.0"/></head>' +
    '<body style="margin:0;padding:0;background-color:' + C.bgPage + ';">' +
    '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background-color:' + C.bgPage + ';">' +
    '<tr><td align="center" style="padding:32px 16px;">' +
    '<table role="presentation" width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%;">' +
      '<tr><td style="padding:0 0 24px 0;"><table role="presentation" cellpadding="0" cellspacing="0"><tr>' +
        '<td style="width:3px;background-color:' + C.terra + ';border-radius:2px;" width="3">&nbsp;</td>' +
        '<td style="padding-left:10px;font-family:' + F + ';font-size:18px;font-weight:700;color:' + C.dark + ';">Neurolia Immo</td>' +
      '</tr></table></td></tr>' +
      '<tr><td><table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background-color:#FFFFFF;border-radius:6px;overflow:hidden;">' +
        '<tr><td style="height:3px;background-color:' + C.terra + ';font-size:0;line-height:0;">&nbsp;</td></tr>' +
        '<tr><td style="padding:32px 28px;font-family:' + F + ';font-size:15px;line-height:1.6;color:' + C.text + ';">' + inner + '</td></tr>' +
      '</table></td></tr>' +
      '<tr><td style="padding:24px 0 0 0;text-align:center;font-family:' + F + ';font-size:12px;color:#999999;">Neurolia Immo &mdash; par Neurolia</td></tr>' +
    '</table></td></tr></table></body></html>';

  return { json: { to: owner.email, subject: subject, html: html } };
});

// ============================================================
// WF03 — Emails staff (Neurolia Immo branded)
// ============================================================

const tasks = $("Taches menage aujourd'hui + demain").all().map(i => i.json);
const allUsers = $("Get tous les owners").all().map(i => i.json);
const properties = $("Get properties").all().map(i => i.json);

const allReservations = [
  ...$("Check-ins aujourd'hui").all().map(i => i.json),
  ...$("Check-outs aujourd'hui").all().map(i => i.json),
  ...$("Check-ins demain").all().map(i => i.json),
];

const DASHBOARD_URL = $('Config').first().json.DASHBOARD_URL;

const resvMap = {};
for (const r of allReservations) resvMap[r.id] = r;
const userMap = {};
for (const u of allUsers) userMap[u.id] = u;
const propMap = {};
for (const p of properties) propMap[p.id] = p;

// --- Colors & Font ---
const C = {
  terra: '#C45C3B', terraLight: '#FBEAE4',
  dark: '#2D2D2D', text: '#4A4A4A', muted: '#888888',
  border: '#E8E6E3', bgPage: '#F5F4F1', bgSunken: '#FAFAF8',
  error: '#DC2626', info: '#2563EB', warningBg: '#FEF3C7', warning: '#D97706',
};
const F = "-apple-system,'Segoe UI',Helvetica,Arial,sans-serif";

// --- Group by staff ---
const staffMap = new Map();
for (const task of tasks) {
  if (task.status === 'completed' || !task.assigned_to) continue;
  const staffId = task.assigned_to;
  const staffUser = userMap[staffId];
  if (!staffMap.has(staffId)) {
    staffMap.set(staffId, {
      staffName: staffUser ? staffUser.full_name : 'Inconnu',
      staffEmail: staffUser ? staffUser.email : null,
      tasks: [],
    });
  }
  const prop = propMap[task.property_id] || {};
  const resv = resvMap[task.reservation_id] || {};
  staffMap.get(staffId).tasks.push({
    propertyName: prop.name || '-',
    propertyAddress: prop.address || '-',
    propertyCity: prop.city || '-',
    accessCode: prop.access_code || '-',
    wifiSsid: prop.wifi_ssid || '-',
    wifiPassword: prop.wifi_password || '-',
    type: task.task_type || task.type,
    scheduledDate: task.scheduled_date,
    nbGuests: resv.nb_guests || '-',
    arrivalTime: resv.arrival_time || 'non renseignee',
    guestName: resv.guest_name || '-',
    specialRequests: resv.special_requests || null,
  });
}

// --- Build emails ---
const todayDate = new Date().toISOString().slice(0, 10);
const todayStr = new Date().toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long' });
const emails = [];

for (const [, staff] of staffMap) {
  if (!staff.staffEmail) continue;
  const firstName = staff.staffName.split(' ')[0];

  // Task cards
  let taskCards = '';
  for (const task of staff.tasks) {
    const isToday = task.scheduledDate === todayDate;
    const borderColor = isToday ? C.error : C.info;
    const dateLabel = isToday ? "Aujourd'hui" : 'Demain';
    const typeLabel = task.type === 'checkout_clean' ? 'Menage depart'
      : task.type === 'checkin_prep' ? 'Preparation arrivee'
      : task.type === 'deep_clean' ? 'Nettoyage approfondi' : 'Tache';

    let specialHtml = '';
    if (task.specialRequests) {
      specialHtml = `<tr><td style="padding:8px 16px 12px;"><div style="background:${C.warningBg};border-radius:4px;padding:8px 12px;font-family:${F};font-size:13px;"><strong style="color:${C.warning};">Demande speciale :</strong> ${task.specialRequests}</div></td></tr>`;
    }

    taskCards += `
<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="margin:12px 0;border-radius:6px;overflow:hidden;border:1px solid ${C.border};">
<tr><td style="height:3px;background-color:${borderColor};font-size:0;line-height:0;">&nbsp;</td></tr>
<tr><td style="padding:16px;">
<table role="presentation" width="100%" cellpadding="0" cellspacing="0">
<tr>
<td style="font-family:${F};font-size:15px;font-weight:700;color:${C.dark};">${typeLabel}</td>
<td align="right" style="font-family:${F};font-size:12px;font-weight:600;color:${borderColor};text-transform:uppercase;letter-spacing:0.06em;">${dateLabel}</td>
</tr>
</table>
<p style="margin:8px 0 4px;font-family:${F};font-size:14px;font-weight:600;color:${C.dark};">${task.propertyName}</p>
<p style="margin:2px 0;font-family:${F};font-size:13px;">
<a href="https://maps.google.com/?q=${encodeURIComponent(task.propertyAddress + ', ' + task.propertyCity)}" style="color:${C.terra};text-decoration:none;">${task.propertyAddress}, ${task.propertyCity}</a>
</p>
<table role="presentation" cellpadding="0" cellspacing="0" style="margin:12px 0 0;font-family:${F};font-size:13px;color:${C.text};">
<tr><td style="padding:2px 12px 2px 0;color:${C.muted};font-size:12px;">Code</td><td style="font-weight:600;">${task.accessCode}</td></tr>
<tr><td style="padding:2px 12px 2px 0;color:${C.muted};font-size:12px;">WiFi</td><td>${task.wifiSsid} / ${task.wifiPassword}</td></tr>
<tr><td style="padding:2px 12px 2px 0;color:${C.muted};font-size:12px;">Voyageur</td><td>${task.guestName} (${task.nbGuests} pers.)</td></tr>
<tr><td style="padding:2px 12px 2px 0;color:${C.muted};font-size:12px;">Arrivee</td><td>${task.arrivalTime}</td></tr>
</table>
</td></tr>
${specialHtml}
</table>`;
  }

  // KPI
  const todayTasks = staff.tasks.filter(t => t.scheduledDate === todayDate).length;
  const tomorrowTasks = staff.tasks.length - todayTasks;

  const content = `
<h1 style="font-family:${F};font-size:22px;font-weight:700;color:${C.dark};margin:0 0 4px;">Bonjour ${firstName}</h1>
<p style="font-family:${F};font-size:14px;color:${C.muted};margin:0 0 20px;">Voici ton planning pour aujourd'hui et demain.</p>
<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:${C.bgSunken};border-radius:6px;margin:0 0 16px;">
<tr>
<td width="50%" style="text-align:center;padding:14px 8px;">
<div style="font-family:${F};font-size:28px;font-weight:700;color:${C.dark};">${todayTasks}</div>
<div style="font-family:${F};font-size:11px;font-weight:500;text-transform:uppercase;letter-spacing:0.06em;color:${C.muted};margin-top:4px;">Aujourd'hui</div>
</td>
<td width="50%" style="text-align:center;padding:14px 8px;">
<div style="font-family:${F};font-size:28px;font-weight:700;color:${C.dark};">${tomorrowTasks}</div>
<div style="font-family:${F};font-size:11px;font-weight:500;text-transform:uppercase;letter-spacing:0.06em;color:${C.muted};margin-top:4px;">Demain</div>
</td>
</tr>
</table>
${taskCards}
<table role="presentation" cellpadding="0" cellspacing="0" style="margin:24px auto 0;">
<tr><td style="background-color:${C.terra};border-radius:4px;">
<a href="${DASHBOARD_URL}/cleaning" style="display:inline-block;padding:12px 28px;font-family:${F};font-size:14px;font-weight:600;color:#FFFFFF;text-decoration:none;">Voir mon planning &rarr;</a>
</td></tr>
</table>`;

