var res = []
  .concat($("Check-ins aujourd'hui").all().map(i => i.json))
  .concat($("Check-outs aujourd'hui").all().map(i => i.json))
  .concat($("Check-ins demain").all().map(i => i.json));

var guestIdsSet = {};
for (var i = 0; i < res.length; i++) {
  var gid = res[i] && res[i].guest_id;
  if (gid) guestIdsSet[gid] = true;
}

var guestIds = Object.keys(guestIdsSet);

if (guestIds.length === 0) {
  return [{ json: { filterString: "id=is.null" } }];
}

// UUID => on quote
var inList = guestIds.map(function(id){ return '"' + id + '"'; }).join(",");

return [{ json: { filterString: "id=in.(" + inList + ")" } }];

// STOP si rien à faire aujourd'hui + demain
// Si on retourne [], le workflow s'arrête ici et aucun mail ne part.

var checkInsToday = $("Check-ins aujourd'hui").all();
var checkOutsToday = $("Check-outs aujourd'hui").all();
var checkInsTomorrow = $("Check-ins demain").all();
var tasks = $("Taches menage aujourd'hui + demain").all();

// Optionnel : si tu as un node "Check-outs demain"
var checkOutsTomorrow = [];
try {
  checkOutsTomorrow = $("Check-outs demain").all();
} catch (e) {
  checkOutsTomorrow = [];
}

// IMPORTANT : si tu veux compter uniquement les tâches non terminées,
// c'est déjà le cas si ton node Supabase filtre status!=completed.
// Sinon tu peux filtrer ici.
var total =
  checkInsToday.length +
  checkOutsToday.length +
  checkInsTomorrow.length +
  checkOutsTomorrow.length +
  tasks.length;

if (total === 0) {
  return []; // STOP: rien à faire => aucun email
}

// Laisse passer UN seul item (évite de propager des duplications)
return [{ json: { ok: true, total: total } }];
